import React, { useState, useEffect } from 'react';
import './App.css';  // Import the CSS file

const API_BASE = 'http://localhost:80/api';

function App() {
    const [selectedBackend, setSelectedBackend] = useState('nodejs');
    const [backends, setBackends] = useState([
        { id: 'nodejs', name: 'Node.js', tech: 'JavaScript', icon: '💚', status: 'unknown', activeBackend: null },
        { id: 'fastapi', name: 'FastAPI', tech: 'Python', icon: '🐍', status: 'unknown', activeBackend: null },
        { id: 'springboot', name: 'Spring Boot', tech: 'Java', icon: '🍃', status: 'unknown', activeBackend: null },
        { id: 'dotnet', name: '.NET', tech: 'C#', icon: '🔷', status: 'unknown', activeBackend: null }
    ]);
    const [tasks, setTasks] = useState([]);
    const [title, setTitle] = useState('');
    const [description, setDescription] = useState('');
    const [message, setMessage] = useState('');
    const [messageType, setMessageType] = useState('success');
    const [loading, setLoading] = useState(false);
    const [activeBackendName, setActiveBackendName] = useState('');

    // Check health of all backends
    const checkAllBackends = async () => {
        const updatedBackends = [...backends];
        for (let i = 0; i < updatedBackends.length; i++) {
            try {
                const response = await fetch(`${API_BASE}/${updatedBackends[i].id}/health`);
                const data = await response.json();
                if (response.ok) {
                    updatedBackends[i].status = 'online';
                    updatedBackends[i].activeBackend = data.backend;
                } else {
                    updatedBackends[i].status = 'offline';
                }
            } catch (error) {
                updatedBackends[i].status = 'offline';
            }
        }
        setBackends(updatedBackends);
    };

    // Fetch tasks from selected backend
    const fetchTasks = async (backendId = selectedBackend) => {
        setLoading(true);
        try {
            const response = await fetch(`${API_BASE}/${backendId}/tasks`);
            const data = await response.json();
            if (data.success) {
                setTasks(data.data);
                setActiveBackendName(data.backend);
                showMessage(`✨ Connected to ${data.backend} via Nginx Load Balancer`, 'success');
            } else {
                showMessage(`Failed to fetch tasks from ${backendId}`, 'error');
            }
        } catch (error) {
            showMessage(`Error: Cannot connect to ${backendId}`, 'error');
            setTasks([]);
        }
        setLoading(false);
    };

    // Select backend when clicking on card
    const selectBackend = (backendId) => {
        if (backends.find(b => b.id === backendId)?.status === 'online') {
            setSelectedBackend(backendId);
            fetchTasks(backendId);
        } else {
            showMessage(`${backendId} is offline. Please check the backend service.`, 'error');
        }
    };

    // Add new task
    const addTask = async (e) => {
        e.preventDefault();
        if (!title.trim()) {
            showMessage('Please enter a task title', 'error');
            return;
        }

        try {
            const response = await fetch(`${API_BASE}/${selectedBackend}/tasks`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ title, description })
            });
            const data = await response.json();
            if (data.success) {
                showMessage('✅ Task added successfully!', 'success');
                setTitle('');
                setDescription('');
                fetchTasks();
            } else {
                showMessage('Error adding task', 'error');
            }
        } catch (error) {
            showMessage('Error adding task', 'error');
        }
    };

    // Delete task
    const deleteTask = async (id) => {
        if (window.confirm('Are you sure you want to delete this task?')) {
            try {
                await fetch(`${API_BASE}/${selectedBackend}/tasks/${id}`, {
                    method: 'DELETE'
                });
                showMessage('🗑️ Task deleted successfully!', 'success');
                fetchTasks();
            } catch (error) {
                showMessage('Error deleting task', 'error');
            }
        }
    };

    const showMessage = (msg, type) => {
        setMessage(msg);
        setMessageType(type);
        setTimeout(() => setMessage(''), 3000);
    };

    useEffect(() => {
        checkAllBackends();
        fetchTasks();
        const interval = setInterval(checkAllBackends, 30000);
        return () => clearInterval(interval);
    }, []);

    return (
        <div className="container">
            <div className="header">
                <h1>🚀 Multi-Backend Task Manager</h1>
                <p>React → Nginx Load Balancer → FastAPI | Node.js | Spring Boot | .NET → MySQL</p>
            </div>

            {message && (
                <div className={`message ${messageType}`}>
                    <span>{message}</span>
                    <button className="close-btn" onClick={() => setMessage('')}>×</button>
                </div>
            )}

            <div className="backends-grid">
                {backends.map(backend => (
                    <div 
                        key={backend.id}
                        className={`backend-card ${backend.id} ${backend.status === 'offline' ? 'offline' : ''} ${selectedBackend === backend.id ? 'active' : ''}`}
                        onClick={() => selectBackend(backend.id)}
                    >
                        <div className="backend-header">
                            <div className="backend-name">
                                {backend.icon} {backend.name}
                            </div>
                            <div>
                                <span className={`status-badge ${backend.status === 'online' ? 'status-online' : 'status-offline'}`}>
                                    {backend.status === 'online' ? '🟢 Online' : '🔴 Offline'}
                                </span>
                            </div>
                        </div>
                        <div className="backend-tech">
                            <span className="tech-icon">{backend.icon}</span>
                            {backend.tech}
                        </div>
                        {selectedBackend === backend.id && backend.status === 'online' && (
                            <div className="active-badge">
                                ✨ Active Backend ✨
                            </div>
                        )}
                        {backend.status === 'online' && backend.activeBackend && (
                            <div style={{ fontSize: '11px', marginTop: '10px', color: '#888', textAlign: 'center' }}>
                                🚀 Load Balanced
                            </div>
                        )}
                    </div>
                ))}
            </div>

            <div className="loadbalancer-info">
                <strong>⚡ Active Backend:</strong> {activeBackendName || 'None'} 
                <span style={{ marginLeft: '10px' }}>→ Nginx Load Balancer (Round Robin) ←</span>
            </div>

            <div className="task-form">
                <h3>➕ Add New Task</h3>
                <form onSubmit={addTask}>
                    <div className="form-group">
                        <input
                            type="text"
                            placeholder="📝 Task Title"
                            value={title}
                            onChange={(e) => setTitle(e.target.value)}
                            required
                        />
                    </div>
                    <div className="form-group">
                        <textarea
                            placeholder="📄 Task Description"
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            rows="3"
                        />
                    </div>
                    <button type="submit">✨ Add Task</button>
                </form>
            </div>

            <div className="tasks-table">
                <table>
                    <thead>
                        <tr>
                            <th>ID</th>
                            <th>Title</th>
                            <th>Description</th>
                            <th>Status</th>
                            <th>Created At</th>
                            <th>Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        {loading ? (
                            <tr>
                                <td colSpan="6" className="loading">
                                    <div className="loading-spinner"></div>
                                    <div style={{ marginTop: '10px' }}>Loading tasks...</div>
                                </td>
                            </tr>
                        ) : tasks.length === 0 ? (
                            <tr>
                                <td colSpan="6" style={{ textAlign: 'center', padding: '40px' }}>
                                    📭 No tasks found. Add your first task above!
                                </td>
                            </tr>
                        ) : (
                            tasks.map(task => (
                                <tr key={task.id}>
                                    <td>#{task.id}</td>
                                    <td><strong>{task.title}</strong></td>
                                    <td>{task.description || '—'}</td>
                                    <td>
                                        <span className={task.status === 'completed' ? 'status-completed' : 'status-pending'}>
                                            {task.status === 'completed' ? '✓ Completed' : '⏳ Pending'}
                                        </span>
                                    </td>
                                    <td>{new Date(task.created_at).toLocaleString()}</td>
                                    <td>
                                        <button onClick={() => deleteTask(task.id)} className="delete-btn">
                                            🗑️ Delete
                                        </button>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

export default App;
